/**************************************************************************************
Добавление/обновление родительского сообщения и добавление дочернего
**************************************************************************************/ create or replace function FeedSaveMessage( PARENT_SUBJECT text, --$1 PARENT_TEXT text, --$2 PARENT_TEXTHTML text, --$3 PARENT_ACTIONUID uuid, --$4 PARENT_ACTIONOBJECTUID uuid, --$5 PARENT_ACTIONOBJECTID bigint, --$6 PARENT_CREATIONDATE timestamp, --$7 PARENT_CREATIONAUTHOR bigint, --$8 PARENT_MESSAGEATTACHMENTS bytea, --$9 PARENT_OBJECTRECIPIENTS bytea, --$10 PARENT_MESSAGEOBJECTS bytea, --$11 PARENT_URL varchar(2000), --$12 &&Subject&& text, --$13 &&Text&& text, --$14 &&TextHtml&& text, --$15 &&ActionUid&& uuid, --$16 &&ActionObjectUid&& uuid, --$17 &&ActionObjectId&& bigint, --$18 &&CreationAuthor&& bigint, --$19 &&MessageAttachments&& bytea, --$20 &&ObjectRecipients&& bytea, --$21 &&MessageObjects&& bytea, --$22 &&Url&& varchar(2000), --$23 &&SaveComment&& smallint, --$24 &&ChangeDate&& timestamp, --$25 &&ChangeDateHash&& char(16), --$26 &&Recipients&& text, --$27 &&SetReadForAuthor&& smallint, --$28 &&IdRangeStart&& bigint, --$29 &&CheckParent&& smallint, --$30 &&DateTimeNow&& timestamp --$31 ) returns void
as $$
declare &&FeedId&& bigint; v_IsRead smallint; Parent_IsRead smallint; Parent_HasUnreadChild smallint; v_TableRecord record; v_missing_recipients bigint; rows_count bigint := 0;
begin
create temporary table if not exists &&FeedRecipients&& ( &&Id&& bigint, &&Priority&& integer ) on commit delete rows;
delete from &&FeedRecipients&&; insert into &&FeedRecipients&& (&&Id&&, &&Priority&&) select distinct cast(substring(val from 1 for position(':' in val) - 1) as bigint), cast(substring(val from position(':' in val) + 1 for char_length(val) - position(':' in val)) as int) from SplitString(&&Recipients&&, ',');
create temporary table if not exists &&FeedSaveTempUpdate&& (&&Id&& bigint, &&ChildCount&& integer, &&IsRead&& smallint, &&ReadDate&& timestamp, &&HasUnreadChild&& smallint, &&UnreadCount&& integer, &&Priority&& integer, &&Recipient&& bigint, &&ParentObjectId&& bigint, &&ParentObjectUid&& uuid) on commit delete rows;
create temporary table if not exists &&FeedSaveTempInsert&& ( &&Id&& bigint, &&Subject&& text, &&Text&& text, &&TextHtml&& text, &&ActionObjectUid&& uuid, &&ActionUid&& uuid, &&ActionObjectId&& bigint not null, &&Recipient&& bigint not null, &&CreationDate&& timestamp not null, &&ChangeDate&& timestamp not null, &&CreationAuthor&& bigint, &&IsParent&& smallint not null, &&ParentObjectId&& bigint, &&ParentObjectUid&& uuid, &&ChildCount&& integer, &&IsRead&& smallint, &&ReadDate&& timestamp, &&HasUnreadChild&& smallint, &&UnreadCount&& integer, &&Priority&& integer, &&ChangeDateHash&& varchar(35) not null, &&MessageAttachments&& bytea, &&ObjectRecipients&& bytea, &&MessageObjects&& bytea, &&Url&& text ) on commit delete rows;
if (&&CheckParent&& = 1) then begin insert into &&FeedSaveTempUpdate&& ( &&Id&&, &&HasUnreadChild&&, &&IsRead&&, &&ReadDate&&, &&UnreadCount&&, &&ChildCount&&, &&Priority&&, &&Recipient&&, &&ParentObjectId&&, &&ParentObjectUid&& ) select fd.&&Id&&, fd.&&HasUnreadChild&&, fd.&&IsRead&&, fd.&&ReadDate&&, fd.&&UnreadCount&&, fd.&&ChildCount&&, fd.&&Priority&&, fd.&&Recipient&&, fd.&&ParentObjectId&&, fd.&&ParentObjectUid&& from &&Feed&& fd inner join &&FeedRecipients&& r on fd.&&Recipient&& = r.&&Id&& where &&IsParent&& = 1 and &&ParentObjectId&& = PARENT_ACTIONOBJECTID and &&ParentObjectUid&& = PARENT_ACTIONOBJECTUID;
create temporary table if not exists &&FeedMissingRecipients&& (&&Recipient&& bigint) on commit delete rows;
insert into &&FeedMissingRecipients&& (&&Recipient&&) select tr.&&Id&& from &&FeedRecipients&& tr left join &&FeedSaveTempUpdate&& tu on tr.&&Id&& = tu.&&Recipient&& group by tr.&&Id&&, tu.&&ParentObjectId&&, tu.&&ParentObjectUid&& having count(tu.&&Recipient&&) = 0;
SELECT COUNT(&&Recipient&&) INTO v_missing_recipients FROM &&FeedMissingRecipients&&;
if (v_missing_recipients > 0) then begin insert into &&FeedSaveTempInsert&& ( &&Id&&, &&ChangeDateHash&&, &&Subject&&, &&Text&&, &&TextHtml&&, &&CreationDate&&, &&ChangeDate&&, &&CreationAuthor&&, &&HasUnreadChild&&, &&ActionUid&&, &&ActionObjectUid&&, &&ActionObjectId&&, &&Recipient&&, &&ParentObjectId&&, &&ParentObjectUid&&, &&IsRead&&, &&ReadDate&&, &&UnreadCount&&, &&Priority&&, &&ChildCount&&, &&IsParent&&, &&MessageAttachments&&, &&ObjectRecipients&&, &&MessageObjects&&, &&Url&& ) select a.&&Id&&, case when a.&&IsParent&& = 1 then $26 || lpad(cast(a.&&Id&& as varchar(19)), 19, '0') else a.&&ChangeDateHash&& end, a.&&Subject&&, a.&&Text&&, a.&&TextHtml&&, a.&&CreationDate&&, a.&&ChangeDate&&, a.&&CreationAuthor&&, a.&&HasUnreadChild&&, a.&&ActionUid&&, a.&&ActionObjectUid&&, a.&&ActionObjectId&&, a.&&Recipient&&, a.&&ParentObjectId&&, a.&&ParentObjectUid&&, a.&&IsRead&&, a.&&ReadDate&&, a.&&UnreadCount&&, a.&&Priority&&, a.&&ChildCount&&, a.&&IsParent&&, a.&&MessageAttachments&&, a.&&ObjectRecipients&&, a.&&MessageObjects&&, a.&&Url&& from &&FeedArchive&& a where a.&&ParentObjectId&& = PARENT_ACTIONOBJECTID and a.&&ParentObjectUid&& = PARENT_ACTIONOBJECTUID and a.&&Recipient&& in (select r.&&Id&& from &&FeedRecipients&& r) and ( (a.&&IsParent&& = 0 and not exists (select u.&&Id&& from &&FeedSaveTempUpdate&& u where u.&&Recipient&& = a.&&Recipient&&)) or (a.&&IsParent&& = 1 and not a.&&Id&& in (select u.&&Id&& from &&FeedSaveTempUpdate&& u where u.&&Recipient&& = a.&&Recipient&&)) ); end; end if; end; end if;
for v_TableRecord in select fr.&&Id&& as &&RecipientId&&, fr.&&Priority&& as &&Priority&& from &&FeedRecipients&& fr loop begin Parent_HasUnreadChild = &&SaveComment&&; v_IsRead = 0; Parent_IsRead = 0; if (&&SetReadForAuthor&& = 1) then begin if (&&SaveComment&& = 0) then begin if (v_TableRecord.&&RecipientId&& = Parent_CreationAuthor) then begin Parent_IsRead = 1; end; end if; end; else begin Parent_IsRead = 1; if (v_TableRecord.&&RecipientId&& = $19) then begin v_IsRead = 1; Parent_HasUnreadChild = 0; end; end if; end; end if; end; end if;
update &&FeedSaveTempUpdate&& set &&HasUnreadChild&& = Parent_HasUnreadChild, &&IsRead&& = Parent_IsRead, &&ReadDate&& = (case when Parent_IsRead = 1 then $31 else null end), &&UnreadCount&& = Parent_HasUnreadChild, &&ChildCount&& = &&SaveComment&&, &&Priority&& = v_TableRecord.&&Priority&& where &&ParentObjectId&& = Parent_ActionObjectId and &&ParentObjectUid&& = Parent_ActionObjectUid and &&Recipient&& = v_TableRecord.&&RecipientId&&;
get diagnostics rows_count = row_count; if (rows_count = 0) then begin update &&FeedSaveTempInsert&& set &&HasUnreadChild&& = Parent_HasUnreadChild, &&IsRead&& = Parent_IsRead, &&ReadDate&& = (case when Parent_IsRead = 1 then $31 else &&ReadDate&& end), &&UnreadCount&& = Parent_HasUnreadChild, &&ChildCount&& = &&ChildCount&& + &&SaveComment&&, &&Priority&& = v_TableRecord.&&Priority&&, &&Subject&& = Parent_Subject, &&Text&& = Parent_Text, &&TextHtml&& = Parent_TextHtml, &&ChangeDate&& = $25, &&MessageAttachments&& = Parent_MessageAttachments, &&ObjectRecipients&& = Parent_ObjectRecipients, &&MessageObjects&& = Parent_MessageObjects, &&Url&& = Parent_Url where &&IsParent&& = 1 and &&ParentObjectId&& = Parent_ActionObjectId and &&ParentObjectUid&& = Parent_ActionObjectUid and &&Recipient&& = v_TableRecord.&&RecipientId&&;
get diagnostics rows_count = row_count; if (rows_count = 0) then begin &&FeedId&& = &&IdRangeStart&&; &&IdRangeStart&& = &&IdRangeStart&& + 1; insert into &&FeedSaveTempInsert&& ( &&Id&&, &&ChangeDateHash&&, &&Subject&&, &&Text&&, &&TextHtml&&, &&CreationDate&&, &&ChangeDate&&, &&CreationAuthor&&, &&HasUnreadChild&&, &&ActionUid&&, &&ActionObjectUid&&, &&ActionObjectId&&, &&Recipient&&, &&ParentObjectId&&, &&ParentObjectUid&&, &&IsRead&&, &&ReadDate&&, &&UnreadCount&&, &&Priority&&, &&ChildCount&&, &&IsParent&&, &&MessageAttachments&&, &&ObjectRecipients&&, &&MessageObjects&&, &&Url&& ) values (&&FeedId&&, $26 || lpad(cast(&&FeedId&& as varchar(19)), 19, '0'), Parent_Subject, Parent_Text, Parent_TextHtml, Parent_CreationDate, &&ChangeDate&&, Parent_CreationAuthor, Parent_HasUnreadChild, Parent_ActionUid, Parent_ActionObjectUid, Parent_ActionObjectId, v_TableRecord.&&RecipientId&&, Parent_ActionObjectId, Parent_ActionObjectUid, Parent_IsRead, (case when Parent_IsRead = 1 then $31 else null end), Parent_HasUnreadChild, v_TableRecord.&&Priority&&, &&SaveComment&&, 1, Parent_MessageAttachments, Parent_ObjectRecipients, Parent_MessageObjects, Parent_Url); end; end if; end; end if;
if (&&SaveComment&& = 1) then begin &&FeedId&& = &&IdRangeStart&&; &&IdRangeStart&& = &&IdRangeStart&& + 1; insert into &&Feed&& (&&Id&&, &&ChangeDateHash&&, &&Subject&&, &&Text&&, &&TextHtml&&, &&CreationDate&&, &&ChangeDate&&, &&CreationAuthor&&, &&IsRead&&, &&ReadDate&&, &&ActionUid&&, &&ActionObjectUid&&, &&ActionObjectId&&, &&Recipient&&, &&ParentObjectId&&, &&ParentObjectUid&&, &&Priority&&, &&IsParent&&, &&UnreadCount&&, &&ChildCount&&, &&MessageAttachments&&, &&ObjectRecipients&&, &&MessageObjects&&, &&Url&&) values (&&FeedId&&, $26 || lpad(cast(&&FeedId&& as varchar(19)), 19, '0'), $13, $14, $15, $25, $25, $19, v_IsRead, (case when v_IsRead = 1 then $31 else null end), $16, $17, $18, v_TableRecord.&&RecipientId&&, Parent_ActionObjectId, Parent_ActionObjectUid, v_TableRecord.&&Priority&&, 0, 0, 0, $20, $21, $22, $23); end; end if; end; end loop;
insert into &&Feed&& ( &&Id&&, &&ChangeDateHash&&, &&Subject&&, &&Text&&, &&TextHtml&&, &&CreationDate&&, &&ChangeDate&&, &&CreationAuthor&&, &&HasUnreadChild&&, &&IsRead&&, &&ReadDate&&, &&ActionUid&&, &&ActionObjectUid&&, &&ActionObjectId&&, &&Recipient&&, &&ParentObjectId&&, &&ParentObjectUid&&, &&Priority&&, &&IsParent&&, &&UnreadCount&&, &&ChildCount&&, &&MessageAttachments&&, &&ObjectRecipients&&, &&MessageObjects&&, &&Url&& ) select fsti.&&Id&&, fsti.&&ChangeDateHash&&, fsti.&&Subject&&, fsti.&&Text&&, fsti.&&TextHtml&&, fsti.&&CreationDate&&, fsti.&&ChangeDate&&, fsti.&&CreationAuthor&&, fsti.&&HasUnreadChild&&, fsti.&&IsRead&&, fsti.&&ReadDate&&, fsti.&&ActionUid&&, fsti.&&ActionObjectUid&&, fsti.&&ActionObjectId&&, fsti.&&Recipient&&, fsti.&&ParentObjectId&&, fsti.&&ParentObjectUid&&, fsti.&&Priority&&, fsti.&&IsParent&&, fsti.&&UnreadCount&&, fsti.&&ChildCount&&, fsti.&&MessageAttachments&&, fsti.&&ObjectRecipients&&, fsti.&&MessageObjects&&, fsti.&&Url&& from &&FeedSaveTempInsert&& fsti;
for v_TableRecord in select &&Id&& as &&FeedId&&, &&HasUnreadChild&& as Parent_HasUnreadChild, &&IsRead&& as Parent_IsRead, &&ReadDate&& as &&DateTimeNow&&, &&ChildCount&& as &&SaveComment&&, &&Priority&& as &&Priority&& from &&FeedSaveTempUpdate&& loop begin update &&Feed&& set &&ChangeDateHash&& = $26 || lpad(cast(&&Id&& as varchar(19)), 19, '0'), &&Subject&& = Parent_Subject, &&Text&& = Parent_Text, &&TextHtml&& = Parent_TextHtml, &&ChangeDate&& = $25, &&HasUnreadChild&& = (case when v_TableRecord.Parent_HasUnreadChild = 1 then 1 else &&HasUnreadChild&& end), &&ReadDate&& = (case when &&Feed&&.&&ReadDate&& is null then v_TableRecord.&&DateTimeNow&& else &&Feed&&.&&ReadDate&& end), &&UnreadCount&& = coalesce(&&UnreadCount&&, 0) + v_TableRecord.Parent_HasUnreadChild, &&ChildCount&& = &&Feed&&.&&ChildCount&& + v_TableRecord.&&SaveComment&&, &&MessageAttachments&& = Parent_MessageAttachments, &&ObjectRecipients&& = Parent_ObjectRecipients, &&MessageObjects&& = Parent_MessageObjects, &&Priority&& = v_TableRecord.&&Priority&&, &&Url&& = Parent_Url where &&Feed&&.&&Id&& = v_TableRecord.&&FeedId&&; end; end loop;
delete from &&FeedSaveTempInsert&&; delete from &&FeedSaveTempUpdate&&;
end
$$ language plpgsql;

/**************************************************************************************
Получить следующего пользователя для архивации
DateLimit дата архивации LastUserId последний архивированный пользователь
**************************************************************************************/ create or replace function FeedToArchiveRecipient( &&DateLimit&& timestamp, &&LastUserId&& bigint ) returns bigint
as $$
declare v_userId bigint;
begin
v_userId = null;
select f.&&Recipient&& into v_userId from &&Feed&& f where f.&&Recipient&& > $2 and f.&&IsParent&& = 1 and f.&&ChangeDate&& < $1 order by f.&&Recipient&& limit (1);
if (v_userId is null) then begin
select f.&&Recipient&& into v_userId from &&Feed&& f where f.&&IsParent&& = 1 and f.&&ChangeDate&& < $1 order by f.&&Recipient&& limit (1);
end; end if;
return coalesce(v_userId, 0); end
$$ language plpgsql;

/**************************************************************************************
Перенос старых сообщений в архив
**************************************************************************************/ create or replace function FeedToArchive( &&DateLimit&& timestamp, &&LastUserId&& bigint, &&CurrentDate&& timestamp ) returns bigint
as $$
declare v_TableRecord record; v_userId bigint; v_count bigint;
begin
v_userId = null;
select FeedToArchiveRecipient($1, $2) into v_userId;
if (v_userId <> 0) then -- найден следующий пользователь begin
create temporary table if not exists &&FeedToArchiveTemp&& ( &&ParentObjectId&& bigint, &&ParentObjectUid&& uuid, &&ParentChangeDate&& timestamp not null ) on commit delete rows;
create temporary table if not exists &&FeedToArchiveTemp2&& ( &&Id&& bigint ) on commit delete rows;
delete from &&FeedToArchiveTemp&&; delete from &&FeedToArchiveTemp2&&;
insert into &&FeedToArchiveTemp&& (&&ParentObjectId&&, &&ParentObjectUid&&, &&ParentChangeDate&&) select f.&&ParentObjectId&&, f.&&ParentObjectUid&&, f.&&ChangeDate&& from &&Feed&& f left join &&FeedFavorite&& ff on ff.&&ActionObjectId&& = f.&&ParentObjectId&& and ff.&&ActionObjectUid&& = f.&&ParentObjectUid&& and ff.&&Recipient&& = f.&&Recipient&& where f.&&IsParent&& = 1 and f.&&ChangeDate&& < $1 and f.&&Recipient&& = v_userId and not exists (select &&Id&& from &&FeedFavorite&& ff where ff.&&ActionObjectId&& = f.&&ParentObjectId&& and ff.&&ActionObjectUid&& = f.&&ParentObjectUid&& and ff.&&Recipient&& = f.&&Recipient&& and (ff.&&IsDelete&& is null or ff.&&IsDelete&& = 0));
-- если есть что обновлять, то обновляем select count(*) into v_count from &&FeedToArchiveTemp&&; if (v_count <> 0) then begin
-- обновляем архив for v_TableRecord in select distinct a.&&Id&& as pId, a.&&Subject&& as pSubject, a.&&Text&& as pText, a.&&TextHtml&& as pTextHtml, a.&&ActionObjectUid&& as pActionObjectUid, a.&&ActionUid&& as pActionUid, a.&&ActionObjectId&& as pActionObjectId, a.&&Recipient&& as pRecipient, a.&&CreationDate&& as pCreationDate, a.&&ChangeDate&& as pChangeDate, a.&&CreationAuthor&& as pCreationAuthor, a.&&IsParent&& as pIsParent, a.&&ParentObjectId&& as pParentObjectId, a.&&ParentObjectUid&& as pParentObjectUid, a.&&ChildCount&& as pChildCount, a.&&Priority&& as pPriority, a.&&ChangeDateHash&& as pChangeDateHash, a.&&MessageAttachments&& as pMessageAttachments, a.&&ObjectRecipients&& as pObjectRecipients, a.&&MessageObjects&& as pMessageObjects, a.&&Url&& as pUrl from &&FeedArchive&& a inner join &&Feed&& f on f.&&Id&& = a.&&Id&& inner join &&FeedToArchiveTemp&& t on t.&&ParentObjectId&& = f.&&ParentObjectId&& and f.&&ParentObjectUid&& = f.&&ParentObjectUid&& and f.&&Recipient&& = v_userId loop begin update &&FeedArchive&& set &&Id&& = v_TableRecord.pId, &&Subject&& = v_TableRecord.pSubject, &&Text&& = v_TableRecord.pText, &&TextHtml&& = v_TableRecord.pTextHtml, &&ActionObjectUid&& = v_TableRecord.pActionObjectUid, &&ActionUid&& = v_TableRecord.pActionUid, &&ActionObjectId&& = v_TableRecord.pActionObjectId, &&Recipient&& = v_TableRecord.pRecipient, &&CreationDate&& = v_TableRecord.pCreationDate, &&ChangeDate&& = v_TableRecord.pChangeDate, &&CreationAuthor&& = v_TableRecord.pCreationAuthor, &&IsParent&& = v_TableRecord.pIsParent, &&ParentObjectId&& = v_TableRecord.pParentObjectId, &&ParentObjectUid&& = v_TableRecord.pParentObjectUid, &&ChildCount&& = v_TableRecord.pChildCount, &&IsRead&& = 1, &&ReadDate&& = $3, &&HasUnreadChild&& = 0, &&UnreadCount&& = 0, &&Priority&& = v_TableRecord.pPriority, &&ChangeDateHash&& = v_TableRecord.pChangeDateHash, &&MessageAttachments&& = v_TableRecord.pMessageAttachments, &&ObjectRecipients&& = v_TableRecord.pObjectRecipients, &&MessageObjects&& = v_TableRecord.pMessageObjects, &&Url&& = v_TableRecord.pUrl where &&Id&& = v_TableRecord.pID; end; end loop;
-- копируем в архив insert into FeedArchive( &&Id&&, &&Subject&&, &&Text&&, &&TextHtml&&, &&ActionObjectUid&&, &&ActionUid&&, &&ActionObjectId&&, &&Recipient&&, &&CreationDate&&, &&ChangeDate&&, &&CreationAuthor&&, &&IsParent&&, &&ParentObjectId&&, &&ParentObjectUid&&, &&ChildCount&&, &&IsRead&&, &&ReadDate&&, &&HasUnreadChild&&, &&UnreadCount&&, &&Priority&&, &&ChangeDateHash&&, &&MessageAttachments&&, &&ObjectRecipients&&, &&MessageObjects&&, &&Url&& ) select f.&&Id&&, f.&&Subject&&, f.&&Text&&, f.&&TextHtml&&, f.&&ActionObjectUid&&, f.&&ActionUid&&, f.&&ActionObjectId&&, f.&&Recipient&&, f.&&CreationDate&&, f.&&ChangeDate&&, f.&&CreationAuthor&&, f.&&IsParent&&, f.&&ParentObjectId&&, f.&&ParentObjectUid&&, f.&&ChildCount&&, 1, $3, 0, 0, f.&&Priority&&, f.&&ChangeDateHash&&, f.&&MessageAttachments&&, f.&&ObjectRecipients&&, f.&&MessageObjects&&, f.&&Url&& from &&Feed&& f inner join &&FeedToArchiveTemp&& t on t.&&ParentObjectId&& = f.&&ParentObjectId&& and t.&&ParentObjectUid&& = f.&&ParentObjectUid&& and f.&&Recipient&& = v_userId where not exists (select 1 from &&FeedArchive&& where &&Id&& = f.&&Id&&);
-- удаляем из ленты, если не изменилось insert into &&FeedToArchiveTemp2&& (&&Id&&) select f.&&Id&& from &&Feed&& f inner join &&Feed&& fp on fp.&&IsParent&& = 1 and fp.&&ParentObjectId&& = f.&&ParentObjectId&& and fp.&&ParentObjectUid&& = f.&&ParentObjectUid&& and fp.&&Recipient&& = f.&&Recipient&& where f.&&Recipient&& = v_userId and exists (select * from &&FeedToArchiveTemp&& t where t.&&ParentObjectId&& = f.&&ParentObjectId&& and t.&&ParentObjectUid&& = f.&&ParentObjectUid&& and t.&&ParentChangeDate&& = fp.&&ChangeDate&&);
delete from &&Feed&& where exists (select &&Id&& from &&FeedToArchiveTemp2&& t2 where t2.&&Id&& = &&Feed&&.&&Id&&) and not exists(select 1 from &&FeedFavorite&& ff where (ff.&&IsDelete&& is null or ff.&&IsDelete&& = 0) and ff.&&ActionObjectId&& = &&Feed&&.&&ParentObjectId&& and ff.&&ActionObjectUid&& = &&Feed&&.&&ParentObjectUid&& and ff.&&Recipient&& = v_userId);
end; end if; end; end if;
return v_userId; end
$$ language plpgsql;

/**************************************************************************************
Установка сообщениям статуса "прочитано"
**************************************************************************************/ create or replace function FeedSetAsRead( ChangeDateHash char(35), --$1 &&Recipient&& bigint, --$2 &&ActionObjectUid&& uuid, --$3 ActionObjectId bigint, --$4 &&DateTimeNow&& timestamp --$5 ) returns void
as $$
declare pRowCount bigint = 0; pTempUid uuid;
begin
pTempUid = uuid_generate_v4();
create temporary table if not exists &&FeedSetAsReadTemp&& ( &&Uid&& uuid, &&Id&& bigint, &&IsParent&& smallint not null, &&UnreadCount&& integer, &&UnreadCountOld&& integer ) on commit delete rows;
delete from &&FeedSetAsReadTemp&& where &&Uid&& = pTempUid;
insert into &&FeedSetAsReadTemp&& (&&Uid&&, &&Id&&, &&IsParent&&, &&UnreadCount&&, &&UnreadCountOld&&)
select pTempUid, &&Id&&, &&IsParent&&, &&UnreadCount&&, &&UnreadCount&& from &&Feed&& f where f.&&Recipient&& = $2 and f.&&ParentObjectId&& = $4 and f.&&ParentObjectUid&& = $3 and f.&&ChangeDateHash&& <= coalesce($1, 'zzzzzzzzzzzzzzzzzzzzzzzzzzzzzzzzzzz') and ( f.&&IsParent&& = 1 or ( f.&&IsRead&& = 0 and f.&&ChangeDateHash&& <= coalesce($1, 'zzzzzzzzzzzzzzzzzzzzzzzzzzzzzzzzzzz') ) );
select count(&&Id&&) from &&FeedSetAsReadTemp&& where &&Uid&& = pTempUid and &&IsParent&& = 0 into pRowCount;
update &&FeedSetAsReadTemp&& set &&UnreadCount&& = &&UnreadCount&& - pRowCount where &&Uid&& = pTempUid and &&IsParent&& = 1;
update &&Feed&& f set &&IsRead&& = 1, &&ReadDate&& = $5, &&UnreadCount&& = (case when (select t.&&IsParent&& from &&FeedSetAsReadTemp&& t where &&Uid&& = pTempUid and t.&&Id&& = f.&&Id&&) = 1 then (select t.&&UnreadCount&& + (f.&&UnreadCount&& - t.&&UnreadCountOld&&) from &&FeedSetAsReadTemp&& t where &&Uid&& = pTempUid and t.&&Id&& = f.&&Id&&) else f.&&UnreadCount&& end), &&HasUnreadChild&& = (case when (select t.&&IsParent&& from &&FeedSetAsReadTemp&& t where &&Uid&& = pTempUid and t.&&Id&& = f.&&Id&&) = 1 then (select (case when t.&&UnreadCount&& + (f.&&UnreadCount&& - t.&&UnreadCountOld&&) = 0 then 0 else 1 end) from &&FeedSetAsReadTemp&& t where &&Uid&& = pTempUid and t.&&Id&& = f.&&Id&&) else f.&&HasUnreadChild&& end) where exists (select 1 from &&FeedSetAsReadTemp&& t where &&Uid&& = pTempUid and t.&&Id&& = f.&&Id&&);
end
$$ language plpgsql;

/**************************************************************************************
Отметить прочитанными
**************************************************************************************/ create or replace function FeedSetAsReadAll( p_Recipient bigint, &&ChangeDateHashMin&& varchar(35), &&ChangeDateHashMax&& varchar(35), p_Priority integer, &&DateTimeNow&& timestamp ) returns void
as $$
declare v_TableRecord record;
begin
for v_TableRecord in select &&ParentObjectId&&, &&ParentObjectUid&& from &&Feed&& where &&IsParent&& = 1 and &&Recipient&& = $1 and (&&IsRead&& = 0 or &&HasUnreadChild&& = 1) and &&ChangeDateHash&& >= coalesce($2, ' ') and &&ChangeDateHash&& <= coalesce($3, 'zzzzzzzzzzzzzzzzzzzzzzzzzzzzzzzzzzz') and ($4 is null or &&Priority&& >= $4) loop begin update &&Feed&& set &&IsRead&& = 1, &&ReadDate&& = $5, &&UnreadCount&& = 0, &&HasUnreadChild&& = 0 where &&Recipient&& = $1 and (&&IsRead&& = 0 or &&HasUnreadChild&& = 1) and &&ParentObjectId&& = v_TableRecord.&&ParentObjectId&& and &&ParentObjectUid&& = v_TableRecord.&&ParentObjectUid&&; end; end loop;
end
$$ language plpgsql;


/**************************************************************************************

   Фильтрация сообщений

**************************************************************************************/
create or replace function FeedLoad(
    &&MaxCount&& integer,            --$1
    &&MaxChildCount&& integer,        --$2
    p_ChangeDateHash varchar(35),    --$3
    p_Recipient bigint,            --$4
    p_Priority integer,        --$5
    &&AllMessages&& smallint        --$6
)
returns table(
    &&Id&& bigint,
    &&Subject&& text,
    &&Text&& text,
    &&TextHtml&& text,
    &&ActionObjectUid&& uuid,
    &&ActionUid&& uuid,
    &&ActionObjectId&& bigint,
    &&Recipient&& bigint,
    &&CreationDate&& timestamp,
    &&ChangeDate&& timestamp,
    &&CreationAuthor&& bigint,
    &&IsParent&& smallint,
    &&ParentObjectId&& bigint,
    &&ParentObjectUid&& uuid,
    &&IsRead&& smallint,
    &&ReadDate&& timestamp,
    &&HasUnreadChild&& smallint,
    &&UnreadCount&& integer,
    &&Priority&& integer,
    &&ChangeDateHash&& varchar(35),
    &&ChildCount&& integer,
    &&MessageAttachments&& bytea,
    &&ObjectRecipients&& bytea,
    &&MessageObjects&& bytea,
    &&Url&& varchar(2000))

as
$$

declare
v_TableRecord record;
v_TableRecord2 record;
v_ResultId bigint;

begin

    p_ChangeDateHash = coalesce(p_ChangeDateHash, 'zzzzzzzzzzzzzzzzzzzzzzzzzzzzzzzzzzz');

    for v_TableRecord in
        select f.&&ParentObjectUid&& as v_ParentObjectUid, f.&&ParentObjectId&& as v_ParentObjectId
        from &&Feed&& f
        where
            f.&&IsParent&& = 1
            and f.&&Recipient&& = $4
            and f.&&ChangeDateHash&& < p_ChangeDateHash
            and f.&&Priority&& >= coalesce($5, 0)
            and ($6 = 1 or f.&&HasUnreadChild&& = 1 or f.&&IsRead&& = 0)
        order by f.&&ChangeDateHash&& desc
        limit ($1)
    loop
        begin
            -- parents
            for v_TableRecord2 in
                select f.&&Id&&, f.&&Subject&&, f.&&Text&& as &&Text&&, f.&&TextHtml&&, f.&&ActionObjectUid&&, f.&&ActionUid&&, f.&&ActionObjectId&&, f.&&Recipient&&, f.&&CreationDate&&,
                    f.&&ChangeDate&&, f.&&CreationAuthor&&, f.&&IsParent&&, f.&&ParentObjectId&&, f.&&ParentObjectUid&&,
                    f.&&IsRead&&, f.&&ReadDate&&,
                    f.&&HasUnreadChild&&, f.&&UnreadCount&&, f.&&Priority&&, f.&&ChangeDateHash&&, f.&&ChildCount&&,
                    f.&&MessageAttachments&&, f.&&ObjectRecipients&&, f.&&MessageObjects&&, f.&&Url&&
                from &&Feed&& f
                where f.&&IsParent&& = 1 and
                    f.&&Recipient&& = $4 and
                    f.&&ParentObjectUid&& = v_TableRecord.v_ParentObjectUid and
                    f.&&ParentObjectId&& = v_TableRecord.v_ParentObjectId
            loop
                begin
                    &&Id&& = v_TableRecord2.&&Id&&;
                    &&Subject&& = v_TableRecord2.&&Subject&&;
                    &&Text&& = v_TableRecord2.&&Text&&;
                    &&TextHtml&& = v_TableRecord2.&&TextHtml&&;
                    &&ActionObjectUid&& = v_TableRecord2.&&ActionObjectUid&&;
                    &&ActionUid&& = v_TableRecord2.&&ActionUid&&;
