            end loop;

            -- childs
            for v_TableRecord2 in
                select f.&&Id&&, f.&&Subject&&, f.&&Text&& as &&Text&&, f.&&TextHtml&&, f.&&ActionObjectUid&&, f.&&ActionUid&&, f.&&ActionObjectId&&, f.&&Recipient&&,
