/**************************************************************************************

   Загрузка избранных сообщений

**************************************************************************************/
create or replace function FeedFavoriteLoad (
    &&MaxCount&& bigint,            --$1
    p_Recipient bigint,            --$2    
    p_ChangeDateHash varchar(16)    --$3
)
returns table(
    &&Id&& bigint,
    &&Subject&& text,
    &&Text&& text,
    &&TextHtml&& text,
    &&ActionObjectUid&& uuid,
    &&ActionUid&& uuid,
    &&ActionObjectId&& bigint,
    &&Recipient&& bigint,
    &&CreationDate&& timestamp,
    &&ChangeDate&& timestamp,
    &&CreationAuthor&& bigint,
    &&IsParent&& smallint,
    &&ParentObjectId&& bigint,
    &&ParentObjectUid&& uuid,
    &&IsRead&& smallint,
    &&ReadDate&& timestamp,
    &&HasUnreadChild&& smallint,
    &&UnreadCount&& integer,
    &&Priority&& integer,
    &&ChangeDateHash&& varchar(35),
    &&ChildCount&& integer,
    &&MessageAttachments&& bytea,
    &&ObjectRecipients&& bytea,
    &&MessageObjects&& bytea,
    &&Url&& varchar(2000))

as
$$

declare
v_TableRecord record;

begin

    p_ChangeDateHash = coalesce(p_ChangeDateHash, 'zzzzzzzzzzzzzzzzzzzzzzzzzzzzzzzzzzz');

    create temporary table if not exists &&FeedObjectId&& 
    (
        &&ChangeDateHash&& varchar(35),
        &&ParentObjectUid&& uuid,
        &&ParentObjectId&& bigint,
    &&IsArchive&& smallint
        ) on commit delete rows;

    insert into &&FeedObjectId&& (&&ChangeDateHash&&, &&ParentObjectUid&&, &&ParentObjectId&&)
        select f.&&ChangeDateHash&&, f.&&ActionObjectUid&&, f.&&ActionObjectId&& 
        from (
            select fp.&&ChangeDateHash&&, fp.&&ActionObjectUid&&, fp.&&ActionObjectId&&
            from &&FeedFavorite&& fp
            where fp.&&Recipient&& = $2
                and fp.&&IsDelete&& = 0
                and fp.&&ChangeDateHash&& < p_ChangeDateHash
            order by fp.&&ChangeDateHash&& desc
            limit ($1)) f;

    create temporary table if not exists &&FeedTempTableFavorite&& 
    (
        &&FavoriteChangeDateHash&& varchar(35),
        &&Id&& bigint, 
        &&Subject&& text, 
        &&Text&& text, 
        &&TextHtml&& text, 
        &&ActionObjectUid&& uuid, 
        &&ActionUid&& uuid, 
        &&ActionObjectId&& bigint not null, 
        &&Recipient&& bigint not null, 
        &&CreationDate&& timestamp not null, 
        &&ChangeDate&& timestamp not null, 
        &&CreationAuthor&& bigint, 
        &&ParentObjectId&& bigint, 
        &&ParentObjectUid&& uuid, 
        &&IsRead&& smallint, 
        &&ReadDate&& timestamp, 
        &&HasUnreadChild&& smallint, 
        &&UnreadCount&& integer, 
        &&Priority&& integer, 
        &&ChangeDateHash&& varchar(35) not null, 
        &&IsParent&& smallint not null,
        &&ChildCount&& integer, 
        &&MessageAttachments&& bytea, 
        &&ObjectRecipients&& bytea, 
        &&MessageObjects&& bytea, 
        &&Url&& text
        ) on commit delete rows;

    -- feed
    insert into &&FeedTempTableFavorite&& (&&FavoriteChangeDateHash&&, &&Id&&, &&Subject&&, &&Text&&, &&TextHtml&&, &&ActionObjectUid&&, &&ActionUid&&, &&ActionObjectId&&, &&Recipient&&, &&CreationDate&&, &&ChangeDate&&, &&CreationAuthor&&, &&ParentObjectId&&, &&ParentObjectUid&&, &&IsRead&&, &&ReadDate&&, &&HasUnreadChild&&, &&UnreadCount&&, &&Priority&&, &&ChangeDateHash&&, &&IsParent&&, &&ChildCount&&, &&MessageAttachments&&, &&ObjectRecipients&&, &&MessageObjects&&, &&Url&&)
        select ft.&&ChangeDateHash&&, fp.&&Id&&, fp.&&Subject&&, fp.&&Text&&, fp.&&TextHtml&&, fp.&&ActionObjectUid&&, fp.&&ActionUid&&, fp.&&ActionObjectId&&, fp.&&Recipient&&, fp.&&CreationDate&&, fp.&&ChangeDate&&, fp.&&CreationAuthor&&, fp.&&ParentObjectId&&, fp.&&ParentObjectUid&&, fp.&&IsRead&&, fp.&&ReadDate&&, fp.&&HasUnreadChild&&, fp.&&UnreadCount&&, fp.&&Priority&&, fp.&&ChangeDateHash&&, fp.&&IsParent&&, fp.&&ChildCount&&, fp.&&MessageAttachments&&, fp.&&ObjectRecipients&&, fp.&&MessageObjects&&, fp.&&Url&&
        from &&Feed&& fp
            inner join &&FeedObjectId&& ft on ft.&&ParentObjectUid&& = fp.&&ParentObjectUid&& and ft.&&ParentObjectId&& = fp.&&ParentObjectId&&
        where fp.&&IsParent&& = 1 and fp.&&Recipient&& = $2;

    -- feed + archive
    for v_TableRecord in 
        select f.&&Id&&, f.&&Subject&&, f.&&Text&&, f.&&TextHtml&&, f.&&ActionObjectUid&&, f.&&ActionUid&&, f.&&ActionObjectId&&, f.&&Recipient&&, f.&&CreationDate&&,
            f.&&ChangeDate&&, f.&&CreationAuthor&&, f.&&ParentObjectId&&, f.&&ParentObjectUid&&,
            f.&&IsRead&&, f.&&ReadDate&&,
            f.&&HasUnreadChild&&, f.&&UnreadCount&&, f.&&Priority&&, f.&&ChangeDateHash&&, f.&&IsParent&&, f.&&ChildCount&&,
            f.&&MessageAttachments&&, f.&&ObjectRecipients&&, f.&&MessageObjects&&, f.&&Url&&
        from (
            select ff.&&FavoriteChangeDateHash&&, ff.&&Id&&, ff.&&Subject&&, ff.&&Text&&, ff.&&TextHtml&&, ff.&&ActionObjectUid&&, 
                ff.&&ActionUid&&, ff.&&ActionObjectId&&, ff.&&Recipient&&, ff.&&CreationDate&&, ff.&&ChangeDate&&,
                ff.&&CreationAuthor&&, ff.&&ParentObjectId&&, ff.&&ParentObjectUid&&, ff.&&IsRead&&, ff.&&ReadDate&&, ff.&&HasUnreadChild&&, 
                ff.&&UnreadCount&&, ff.&&Priority&&, ff.&&ChangeDateHash&&, ff.&&IsParent&&, ff.&&ChildCount&&, ff.&&MessageAttachments&&, 
                ff.&&ObjectRecipients&&, ff.&&MessageObjects&&, ff.&&Url&&
            from &&FeedTempTableFavorite&& ff

            union all

            select ft.&&ChangeDateHash&& &&FavoriteChangeDateHash&&, fp.&&Id&&, fp.&&Subject&&, fp.&&Text&&, fp.&&TextHtml&&, fp.&&ActionObjectUid&&, fp.&&ActionUid&&, fp.&&ActionObjectId&&, fp.&&Recipient&&, fp.&&CreationDate&&, fp.&&ChangeDate&&, fp.&&CreationAuthor&&, fp.&&ParentObjectId&&, fp.&&ParentObjectUid&&, fp.&&IsRead&&, fp.&&ReadDate&&, fp.&&HasUnreadChild&&, fp.&&UnreadCount&&, fp.&&Priority&&, fp.&&ChangeDateHash&&, fp.&&IsParent&&, fp.&&ChildCount&&, fp.&&MessageAttachments&&, fp.&&ObjectRecipients&&, fp.&&MessageObjects&&, fp.&&Url&&
            from &&FeedArchive&& fp right join (
                select t.&&ChangeDateHash&&, t.&&ParentObjectId&&, t.&&ParentObjectUid&& 
                from &&FeedObjectId&& t left join &&FeedTempTableFavorite&& p on p.&&ParentObjectId&& = t.&&ParentObjectId&& and p.&&ParentObjectUid&& = t.&&ParentObjectUid&&
                where p.&&ChangeDateHash&& is null
                ) ft on ft.&&ParentObjectUid&& = fp.&&ParentObjectUid&& and ft.&&ParentObjectId&& = fp.&&ParentObjectId&&
            where fp.&&IsParent&& = 1 and fp.&&Recipient&& = $2
            ) f
        order by &&FavoriteChangeDateHash&& desc
    loop
        begin
            &&Id&& = v_TableRecord.&&Id&&;
            &&Subject&& = v_TableRecord.&&Subject&&;
            &&Text&& = v_TableRecord.&&Text&&;
            &&TextHtml&& = v_TableRecord.&&TextHtml&&;
            &&ActionObjectUid&& = v_TableRecord.&&ActionObjectUid&&;
            &&ActionUid&& = v_TableRecord.&&ActionUid&&;
            &&ActionObjectId&& = v_TableRecord.&&ActionObjectId&&;
            &&Recipient&& = v_TableRecord.&&Recipient&&;
            &&CreationDate&& = v_TableRecord.&&CreationDate&&;
            &&ChangeDate&& = v_TableRecord.&&ChangeDate&&;
            &&CreationAuthor&& = v_TableRecord.&&CreationAuthor&&; 
            &&ParentObjectId&& = v_TableRecord.&&ParentObjectId&&;
            &&ParentObjectUid&& = v_TableRecord.&&ParentObjectUid&&;
            &&IsRead&& = v_TableRecord.&&IsRead&&;
            &&ReadDate&& = v_TableRecord.&&ReadDate&&;
            &&HasUnreadChild&& = v_TableRecord.&&HasUnreadChild&&;
            &&UnreadCount&& = v_TableRecord.&&UnreadCount&&;
            &&Priority&& = v_TableRecord.&&Priority&&;
            &&ChangeDateHash&& = v_TableRecord.&&ChangeDateHash&&;
            &&IsParent&& = v_TableRecord.&&IsParent&&;
            &&ChildCount&& = v_TableRecord.&&ChildCount&&;
            &&MessageAttachments&& = v_TableRecord.&&MessageAttachments&&;
            &&ObjectRecipients&& = v_TableRecord.&&ObjectRecipients&&;
            &&MessageObjects&& = v_TableRecord.&&MessageObjects&&;
            &&Url&& = v_TableRecord.&&Url&&;

            return next;
        end;
    end loop;

    delete from &&FeedObjectId&&;
    delete from &&FeedTempTableFavorite&&;

end

$$
language plpgsql;


/**************************************************************************************

   Загрузка новых сообщений

**************************************************************************************/
create or replace function FeedLoadNew (
    &&MaxCount&& bigint,
    &&MaxChildCount&& bigint,
    p_ChangeDateHash varchar(35),
    p_Recipient bigint,
    &&AllMessages&& smallint
)
returns table(
    &&Id&& bigint,
    &&Subject&& text,
    &&Text&& text,
    &&TextHtml&& text,
    &&ActionObjectUid&& uuid,
    &&ActionUid&& uuid,
    &&ActionObjectId&& bigint,
    &&Recipient&& bigint,
    &&CreationDate&& timestamp,
    &&ChangeDate&& timestamp,
    &&CreationAuthor&& bigint,
    &&IsParent&& smallint,
    &&ParentObjectId&& bigint,
    &&ParentObjectUid&& uuid,
    &&IsRead&& smallint,
    &&ReadDate&& timestamp,
    &&HasUnreadChild&& smallint,
    &&UnreadCount&& integer,
    &&Priority&& integer,
    &&ChangeDateHash&& varchar(35),
    &&ChildCount&& integer,
    &&MessageAttachments&& bytea,
    &&ObjectRecipients&& bytea,
    &&MessageObjects&& bytea,
    &&Url&& varchar(2000))

as
$$

declare
v_TableRecord record;
v_TableRecord2 record;

begin

    p_ChangeDateHash = coalesce(p_ChangeDateHash, '');

    for v_TableRecord in
        select fd.&&ParentObjectUid&& as v_ParentObjectUid, fd.&&ParentObjectId&& as v_ParentObjectId
        from &&Feed&& fd
        where fd.&&IsParent&& = 1
            and fd.&&Recipient&& = p_Recipient
            and fd.&&ChangeDateHash&& > p_ChangeDateHash
            and (&&AllMessages&& = 1 or fd.&&HasUnreadChild&& = 1 or fd.&&IsRead&& = 0)
        order by fd.&&ChangeDateHash&&
        limit(&&MaxCount&&)
    loop
        begin

            -- parents
            for v_TableRecord2 in
                select fd.&&Id&&, fd.&&Subject&&, fd.&&Text&&, fd.&&TextHtml&&, fd.&&ActionObjectUid&&, fd.&&ActionUid&&, fd.&&ActionObjectId&&, fd.&&Recipient&&,
                    fd.&&CreationDate&&, fd.&&ChangeDate&&,
                    fd.&&CreationAuthor&&, fd.&&IsParent&&, fd.&&ParentObjectId&&, fd.&&ParentObjectUid&&, fd.&&IsRead&&, fd.&&ReadDate&&,
                    fd.&&HasUnreadChild&&, fd.&&UnreadCount&&, fd.&&Priority&&, fd.&&ChangeDateHash&&, fd.&&ChildCount&&,
                    fd.&&MessageAttachments&&, fd.&&ObjectRecipients&&, fd.&&MessageObjects&&, fd.&&Url&&
                from &&Feed&& fd
                where fd.&&IsParent&& = 1 and
                    fd.&&Recipient&& = p_Recipient and
                    fd.&&ParentObjectUid&& = v_TableRecord.v_ParentObjectUid and
                    fd.&&ParentObjectId&& = v_TableRecord.v_ParentObjectId
            loop
                begin
                    &&Id&& = v_TableRecord2.&&Id&&;
                    &&Subject&& = v_TableRecord2.&&Subject&&;
                    &&Text&& = v_TableRecord2.&&Text&&;
                    &&TextHtml&& = v_TableRecord2.&&TextHtml&&;
                    &&ActionObjectUid&& = v_TableRecord2.&&ActionObjectUid&&;
                    &&ActionUid&& = v_TableRecord2.&&ActionUid&&;
                    &&ActionObjectId&& = v_TableRecord2.&&ActionObjectId&&;
                    &&Recipient&& = v_TableRecord2.&&Recipient&&;
                    &&CreationDate&& = v_TableRecord2.&&CreationDate&&;
                    &&ChangeDate&& = v_TableRecord2.&&ChangeDate&&;
                    &&CreationAuthor&& = v_TableRecord2.&&CreationAuthor&&;
                    &&IsParent&& = v_TableRecord2.&&IsParent&&;
                    &&ParentObjectId&& = v_TableRecord2.&&ParentObjectId&&;
                    &&ParentObjectUid&& = v_TableRecord2.&&ParentObjectUid&&;
                    &&IsRead&& = v_TableRecord2.&&IsRead&&;
                    &&ReadDate&& = v_TableRecord2.&&ReadDate&&;
                    &&HasUnreadChild&& = v_TableRecord2.&&HasUnreadChild&&;
                    &&UnreadCount&& = v_TableRecord2.&&UnreadCount&&;
                    &&Priority&& = v_TableRecord2.&&Priority&&;
                    &&ChangeDateHash&& = v_TableRecord2.&&ChangeDateHash&&;
                    &&ChildCount&& = v_TableRecord2.&&ChildCount&&;
                    &&MessageAttachments&& = v_TableRecord2.&&MessageAttachments&&;
                    &&ObjectRecipients&& = v_TableRecord2.&&ObjectRecipients&&;
                    &&MessageObjects&& = v_TableRecord2.&&MessageObjects&&;
                    &&Url&& = v_TableRecord2.&&Url&&;
          return next;
                end;
            end loop;

            -- childs
            for v_TableRecord2 in
                select fd.&&Id&&, fd.&&Subject&&, fd.&&Text&&, fd.&&TextHtml&&, fd.&&ActionObjectUid&&, fd.&&ActionUid&&, fd.&&ActionObjectId&&, fd.&&Recipient&&,
                    fd.&&CreationDate&&, fd.&&ChangeDate&&,
                    fd.&&CreationAuthor&&, fd.&&IsParent&&, fd.&&ParentObjectId&&, fd.&&ParentObjectUid&&, fd.&&IsRead&&, fd.&&ReadDate&&,
                    fd.&&HasUnreadChild&&, fd.&&UnreadCount&&, fd.&&Priority&&, fd.&&ChangeDateHash&&, fd.&&ChildCount&&,
                    fd.&&MessageAttachments&&, fd.&&ObjectRecipients&&, fd.&&MessageObjects&&, fd.&&Url&&
                from &&Feed&& fd
                where fd.&&IsParent&& = 0 and
                      fd.&&Recipient&& = p_Recipient and
                      fd.&&ParentObjectUid&& = v_TableRecord.v_ParentObjectUid and
                      fd.&&ParentObjectId&& = v_TableRecord.v_ParentObjectId and
                      fd.&&ChangeDateHash&& > p_ChangeDateHash
                order by fd.&&ChangeDateHash&& desc
                limit(&&MaxChildCount&&)
            loop
                begin
                    &&Id&& = v_TableRecord2.&&Id&&;
                    &&Subject&& = v_TableRecord2.&&Subject&&;
                    &&Text&& = v_TableRecord2.&&Text&&;
                    &&TextHtml&& = v_TableRecord2.&&TextHtml&&;
                    &&ActionObjectUid&& = v_TableRecord2.&&ActionObjectUid&&;
                    &&ActionUid&& = v_TableRecord2.&&ActionUid&&;
                    &&ActionObjectId&& = v_TableRecord2.&&ActionObjectId&&;
                    &&Recipient&& = v_TableRecord2.&&Recipient&&;
                    &&CreationDate&& = v_TableRecord2.&&CreationDate&&;
                    &&ChangeDate&& = v_TableRecord2.&&ChangeDate&&;
                    &&CreationAuthor&& = v_TableRecord2.&&CreationAuthor&&;
                    &&IsParent&& = v_TableRecord2.&&IsParent&&;
                    &&ParentObjectId&& = v_TableRecord2.&&ParentObjectId&&;
                    &&ParentObjectUid&& = v_TableRecord2.&&ParentObjectUid&&;
                    &&IsRead&& = v_TableRecord2.&&IsRead&&;
                    &&ReadDate&& = v_TableRecord2.&&ReadDate&&;
                    &&HasUnreadChild&& = v_TableRecord2.&&HasUnreadChild&&;
                    &&UnreadCount&& = v_TableRecord2.&&UnreadCount&&;
                    &&Priority&& = v_TableRecord2.&&Priority&&;
                    &&ChangeDateHash&& = v_TableRecord2.&&ChangeDateHash&&;
                    &&ChildCount&& = v_TableRecord2.&&ChildCount&&;
                    &&MessageAttachments&& = v_TableRecord2.&&MessageAttachments&&;
                    &&ObjectRecipients&& = v_TableRecord2.&&ObjectRecipients&&;
                    &&MessageObjects&& = v_TableRecord2.&&MessageObjects&&;
                    &&Url&& = v_TableRecord2.&&Url&&;
          return next;
                end;
            end loop;
        end;
    end loop;

end

$$
