/**************************************************************************************

   Загрузка новых сообщений из избранного

**************************************************************************************/
create or replace function FeedFavoriteLoadNew (
    p_ChangeDateHash varchar(16),
    p_Recipient bigint,
    &&MaxCount&& bigint,
    &&AllMessages&& smallint
)
returns table(
    &&Id&& bigint,
    &&Recipient&& bigint,
    &&ActionObjectUid&& uuid,
    &&ActionObjectId&& bigint,
    &&ChangeDateHash&& varchar(16),
    &&IsDelete&& smallint
)

as
$$

declare
v_TableRecord record;

begin

  p_ChangeDateHash = coalesce(p_ChangeDateHash, '');

    for v_TableRecord in 
        select ff.&&Id&&, ff.&&Recipient&&, ff.&&ActionObjectId&&, ff.&&ActionObjectUid&&, ff.&&ChangeDateHash&&, ff.&&IsDelete&&
        from &&FeedFavorite&& ff
        where ff.&&Recipient&& = p_Recipient
            and (ff.&&IsDelete&& = 0 or &&AllMessages&& = 1)
            and ff.&&ChangeDateHash&& > p_ChangeDateHash
        order by ff.&&ChangeDateHash&&
        limit (&&MaxCount&&)
    loop
        begin
            &&Id&& = v_TableRecord.&&Id&&;
            &&Recipient&& = v_TableRecord.&&Recipient&&;
            &&ActionObjectId&& = v_TableRecord.&&ActionObjectId&&;
            &&ActionObjectUid&& = v_TableRecord.&&ActionObjectUid&&;
            &&ChangeDateHash&& = v_TableRecord.&&ChangeDateHash&&;
            &&IsDelete&& = v_TableRecord.&&IsDelete&&;

            return next;
        end;
    end loop;
end

$$
language plpgsql;


/**************************************************************************************

   Загрузка информации по объектам сообщений ленты

**************************************************************************************/
create or replace function FeedInfoLoadNew(
    p_ChangeDate timestamp,
    p_Recipient bigint,
    &&MaxCount&& bigint
)
returns table(
    &&Id&& bigint,
    &&Recipient&& bigint,
    &&ActionObjectUid&& uuid,
    &&ActionObjectId&& bigint,
    &&ChangeDate&& timestamp,
    &&Data&& bytea
)
as
$$

declare
v_TableRecord record;

begin

    for v_TableRecord in
        select i.&&Id&&, i.&&Recipient&&, i.&&ActionObjectId&&, i.&&ActionObjectUid&&, i.&&ChangeDate&&, i.&&Data&&
        from &&FeedInfo&& i
            inner join (
                select i1.&&ActionObjectUid&&, i1.&&ActionObjectId&&, i1.&&Recipient&&, max(i1.&&ChangeDate&&) &&ChangeDate&&
                from &&FeedInfo&& i1
                where i1.&&Recipient&& = p_Recipient
                group by i1.&&ActionObjectUid&&, i1.&&ActionObjectId&&, i1.&&Recipient&&
                ) f 
            on f.&&ActionObjectUid&& = i.&&ActionObjectUid&& and f.&&ActionObjectId&& = i.&&ActionObjectId&& and f.&&Recipient&& = i.&&Recipient&&    and f.&&ChangeDate&& = i.&&ChangeDate&&
        where p_ChangeDate is null or i.&&ChangeDate&& > p_ChangeDate
        order by i.&&ChangeDate&&
        limit(&&MaxCount&&)
    loop
        begin
            &&Id&& = v_TableRecord.&&Id&&;
            &&Recipient&& = v_TableRecord.&&Recipient&&;
            &&ActionObjectId&& = v_TableRecord.&&ActionObjectId&&;
            &&ActionObjectUid&& = v_TableRecord.&&ActionObjectUid&&;
            &&ChangeDate&& = v_TableRecord.&&ChangeDate&&;
            &&Data&& = v_TableRecord.&&Data&&;

                return next;
        end;
    end loop;

end

$$
language plpgsql;


/**************************************************************************************

   Загружает указанное сообщение со всеми комментариями.

**************************************************************************************/
create or replace function FeedMessageLoad(&&MessageId&& bigint)
returns table(
    &&Id&& bigint,
    &&Subject&& text,
    &&Text&& text,
    &&TextHtml&& text,
    &&ActionObjectUid&& uuid,
    &&ActionUid&& uuid,
    &&ActionObjectId&& bigint,
    &&Recipient&& bigint,
    &&CreationDate&& timestamp,
    &&ChangeDate&& timestamp,
    &&CreationAuthor&& bigint,
    &&IsParent&& smallint,
    &&ParentObjectId&& bigint,
    &&ParentObjectUid&& uuid,
    &&IsRead&& smallint,
    &&ReadDate&& timestamp,
    &&HasUnreadChild&& smallint,
    &&UnreadCount&& integer,
    &&Priority&& integer,
    &&ChangeDateHash&& varchar(35),
    &&ChildCount&& integer,
    &&MessageAttachments&& bytea,
    &&ObjectRecipients&& bytea,
    &&MessageObjects&& bytea,
    &&Url&& varchar(2000))

as
$$

declare
v_TableRecord record;

begin

    for v_TableRecord in
        select f.&&Id&&, f.&&Subject&&, f.&&Text&&, f.&&TextHtml&&, f.&&ActionObjectUid&&, f.&&ActionUid&&, f.&&ActionObjectId&&, f.&&Recipient&&, f.&&CreationDate&&,
            f.&&ChangeDate&&, f.&&CreationAuthor&&, f.&&IsParent&&, f.&&ParentObjectId&&, f.&&ParentObjectUid&&,
            f.&&IsRead&&, f.&&ReadDate&&,
            f.&&HasUnreadChild&&, f.&&UnreadCount&&, f.&&Priority&&, f.&&ChangeDateHash&&, f.&&ChildCount&&,
            f.&&MessageAttachments&&, f.&&ObjectRecipients&&, f.&&MessageObjects&&, f.&&Url&&
        from &&Feed&& f inner join &&Feed&& ff on
            ff.&&Id&& = $1
            and ff.&&Recipient&& = f.&&Recipient&&
            and ff.&&ParentObjectId&& = f.&&ParentObjectId&&
            and ff.&&ParentObjectUid&& = f.&&ParentObjectUid&&
        order by f.&&IsParent&& desc, f.&&ChangeDateHash&& desc
    loop
        begin
            &&Id&& = v_TableRecord.&&Id&&;
            &&Subject&& = v_TableRecord.&&Subject&&;
            &&Text&& = v_TableRecord.&&Text&&;
            &&TextHtml&& = v_TableRecord.&&TextHtml&&;
