/**************************************************************************************

   Фильтрация сообщений

**************************************************************************************/
create or replace function FeedSearch(
    &&MaxCount&& bigint,            --$1
    &&MaxChildCount&& bigint,        --$2
    p_ChangeDateHash varchar(35),    --$3
    &&FastSearch&& varchar(255),        --$4
    p_Recipient bigint,            --$5
