)
returns table(
    &&Id&& bigint,
    &&Subject&& text,
    &&Text&& text,
    &&TextHtml&& text,
    &&ActionObjectUid&& uuid,
    &&ActionUid&& uuid,
    &&ActionObjectId&& bigint,
    &&Recipient&& bigint,
    &&CreationDate&& timestamp,
    &&ChangeDate&& timestamp,
    &&CreationAuthor&& bigint,
    &&IsParent&& smallint,
    &&ParentObjectId&& bigint,
    &&ParentObjectUid&& uuid,
    &&IsRead&& smallint,
    &&HasUnreadChild&& smallint,
    &&UnreadCount&& integer,
    &&Priority&& integer,
    &&ChangeDateHash&& varchar(35),
    &&ChildCount&& integer,
    &&MessageAttachments&& bytea,
    &&ObjectRecipients&& bytea,
    &&MessageObjects&& bytea,
    &&Url&& varchar(2000))

as
$$

declare
v_TableRecord record;
v_TableRecord2 record;

begin

    p_ChangeDateHash = coalesce(p_ChangeDateHash, 'zzzzzzzzzzzzzzzzzzzzzzzzzzzzzzzzzzz');

create temporary table if not exists &&FeedObject&&
        (&&ParentObjectId&& bigint not null,
        &&ParentObjectUid&& uuid not null,
        &&IsArchive&& smallint)
        on commit delete rows;

    if ($8 is null) then
        begin
            insert into &&FeedObject&& (&&ParentObjectUid&&, &&ParentObjectId&&)
                select f.&&ParentObjectUid&&, f.&&ParentObjectId&&
                from &&Feed&& f
                where f.&&Recipient&& = $5
                    and f.&&ChangeDate&& >= $6
                    and ($7 is null or f.&&ChangeDate&& <= $7)
                    and f.&&ChangeDateHash&& < p_ChangeDateHash
          and ($9 = 0 or f.&&IsRead&& = 0)
                    and ($4 is null or lower(f.&&Text&&) like $4 or lower(f.&&Subject&&) like $4)
                group by f.&&ParentObjectUid&&, f.&&ParentObjectId&&
                order by max(f.&&ChangeDateHash&&) desc;


            -- parents
            for v_TableRecord in
                select f.&&Id&&, f.&&Subject&&, f.&&Text&&, f.&&TextHtml&&, f.&&ActionObjectUid&&, f.&&ActionUid&&, f.&&ActionObjectId&&, f.&&Recipient&&,
                    f.&&CreationDate&&, f.&&ChangeDate&&, f.&&CreationAuthor&&, f.&&IsParent&&, f.&&ParentObjectId&&, f.&&ParentObjectUid&&, f.&&IsRead&&,
                    f.&&HasUnreadChild&&, f.&&UnreadCount&&, f.&&Priority&&, f.&&ChangeDateHash&&, f.&&ChildCount&&, f.&&MessageAttachments&&, f.&&ObjectRecipients&&, f.&&MessageObjects&&, f.&&Url&&
                from &&Feed&& f
                    right join &&FeedObject&& fo on fo.&&ParentObjectUid&& = f.&&ParentObjectUid&& and fo.&&ParentObjectId&& = f.&&ParentObjectId&&
                where f.&&IsParent&& = 1 and
                    f.&&Recipient&& = $5 and
                    f.&&ChangeDateHash&& < p_ChangeDateHash
                order by f.&&ChangeDateHash&& desc
                limit ($1)
            loop
                begin
                    &&Id&& = v_TableRecord.&&Id&&;
                    &&Subject&& = v_TableRecord.&&Subject&&;
                    &&Text&& = v_TableRecord.&&Text&&;
                    &&TextHtml&& = v_TableRecord.&&TextHtml&&;
                    &&ActionObjectUid&& = v_TableRecord.&&ActionObjectUid&&;
                    &&ActionUid&& = v_TableRecord.&&ActionUid&&;
