                    &&CreationDate&& = v_TableRecord.&&CreationDate&&;
                    &&ChangeDate&& = v_TableRecord.&&ChangeDate&&;
                    &&CreationAuthor&& = v_TableRecord.&&CreationAuthor&&;
                    &&IsParent&& = v_TableRecord.&&IsParent&&;
                    &&ParentObjectId&& = v_TableRecord.&&ParentObjectId&&;
                    &&ParentObjectUid&& = v_TableRecord.&&ParentObjectUid&&;
                    &&IsRead&& = v_TableRecord.&&IsRead&&;
                    &&HasUnreadChild&& = v_TableRecord.&&HasUnreadChild&&;
                    &&UnreadCount&& = v_TableRecord.&&UnreadCount&&;
                    &&Priority&& = v_TableRecord.&&Priority&&;
                    &&ChangeDateHash&& = v_TableRecord.&&ChangeDateHash&&;
                    &&ChildCount&& = v_TableRecord.&&ChildCount&&;
                    &&MessageAttachments&& = v_TableRecord.&&MessageAttachments&&;
                    &&ObjectRecipients&& = v_TableRecord.&&ObjectRecipients&&;
                    &&MessageObjects&& = v_TableRecord.&&MessageObjects&&;
                    &&Url&& = v_TableRecord.&&Url&&;

                    return next;


                    -- дочерние сообщения
                    for v_TableRecord2 in
                        select f.&&Id&&, f.&&Subject&&, f.&&Text&&, f.&&TextHtml&&, f.&&ActionObjectUid&&, f.&&ActionUid&&, f.&&ActionObjectId&&, f.&&Recipient&&,
                            f.&&CreationDate&&, f.&&ChangeDate&&, f.&&CreationAuthor&&,
                            f.&&IsRead&&, f.&&HasUnreadChild&&, f.&&UnreadCount&&,
                            f.&&Priority&&, f.&&ChangeDateHash&&, f.&&IsParent&&, f.&&ChildCount&&, f.&&MessageAttachments&&, f.&&ObjectRecipients&&, f.&&MessageObjects&&, f.&&Url&&
                        from &&Feed&& f
                        where f.&&IsParent&& = 0 and
                            f.&&Recipient&& = $5 and
                            f.&&ParentObjectUid&& = v_TableRecord.&&ParentObjectUid&& and
                            f.&&ParentObjectId&& = v_TableRecord.&&ParentObjectId&& and
                            (P_ToDate is null or f.&&ChangeDate&& <= P_ToDate) and
              (P_OnlyUnread = 0 or f.&&IsRead&& = 0) and
                            (&&FastSearch&& is null or lower(f.&&Text&&) like &&FastSearch&& or lower(f.&&Subject&&) like &&FastSearch&&)
                        order by ChangeDateHash desc
                        limit ($1)
                    loop
                        begin
                            &&Id&& = v_TableRecord2.&&Id&&;
                            &&Subject&& = v_TableRecord2.&&Subject&&;
                            &&Text&& = v_TableRecord2.&&Text&&;
                            &&TextHtml&& = v_TableRecord2.&&TextHtml&&;
                            &&ActionObjectUid&& = v_TableRecord2.&&ActionObjectUid&&;
                            &&ActionUid&& = v_TableRecord2.&&ActionUid&&;
                            &&ActionObjectId&& = v_TableRecord2.&&ActionObjectId&&;
                            &&Recipient&& = v_TableRecord2.&&Recipient&&;
                            &&CreationDate&& = v_TableRecord2.&&CreationDate&&;
                            &&ChangeDate&& = v_TableRecord2.&&ChangeDate&&;
                            &&CreationAuthor&& = v_TableRecord2.&&CreationAuthor&&;
                            &&IsParent&& = v_TableRecord2.&&IsParent&&;
                            &&IsRead&& = v_TableRecord2.&&IsRead&&;
                            &&HasUnreadChild&& = v_TableRecord2.&&HasUnreadChild&&;
                            &&UnreadCount&& = v_TableRecord2.&&UnreadCount&&;
                            &&Priority&& = v_TableRecord2.&&Priority&&;
                            &&ChangeDateHash&& = v_TableRecord2.&&ChangeDateHash&&;
                            &&ChildCount&& = v_TableRecord2.&&ChildCount&&;
                            &&MessageAttachments&& = v_TableRecord2.&&MessageAttachments&&;
                            &&ObjectRecipients&& = v_TableRecord2.&&ObjectRecipients&&;
                            &&MessageObjects&& = v_TableRecord2.&&MessageObjects&&;
                            &&Url&& = v_TableRecord2.&&Url&&;

                            return next;
                        end;
                    end loop;
                end;
            end loop;
        end;
    else
        begin

            create temporary table if not exists &&FeedFilterAuthors&& (
          &&Id&& bigint not null primary key
        ) on commit delete rows;

            insert into &&FeedFilterAuthors&&
            select cast(&&Val&& as bigint) as AuthorId from SplitString(P_Authors, ',');

            insert into &&FeedObject&& (&&ParentObjectUid&&, &&ParentObjectId&&)
                select f.&&ParentObjectUid&&, f.&&ParentObjectId&&
                from &&Feed&& f
                where f.&&Recipient&& = p_Recipient
                    and f.&&ChangeDate&& >= P_FromDate
                    and (P_ToDate is null or f.&&ChangeDate&& <= P_ToDate)
                    and f.&&ChangeDateHash&& < p_ChangeDateHash
                    and (P_Authors is null or f.&&CreationAuthor&& in (select ffa.&&Id&& from &&FeedFilterAuthors&& ffa))
          and (P_OnlyUnread = 0 or f.&&IsRead&& = 0)
                    and (&&FastSearch&& is null or lower(f.&&Text&&) like &&FastSearch&& or lower(f.&&Subject&&) like &&FastSearch&&)
                group by f.&&ParentObjectUid&&, f.&&ParentObjectId&&
                order by max(f.&&ChangeDateHash&&) desc;


            -- parents
            for v_TableRecord in
                select f.&&Id&&, f.&&Subject&&, f.&&Text&&, f.&&TextHtml&&, f.&&ActionObjectUid&&, f.&&ActionUid&&, f.&&ActionObjectId&&, f.&&Recipient&&, f.&&CreationDate&&, f.&&ChangeDate&&,
                    f.&&CreationAuthor&&, f.&&IsParent&&, f.&&ParentObjectId&&, f.&&ParentObjectUid&&, f.&&IsRead&&,
                    f.&&HasUnreadChild&&, f.&&UnreadCount&&, f.&&Priority&&, f.&&ChangeDateHash&&, f.&&ChildCount&&, f.&&MessageAttachments&&, f.&&ObjectRecipients&&, f.&&MessageObjects&&, f.&&Url&&
                from &&Feed&& f
                    right join &&FeedObject&& fo on fo.&&ParentObjectUid&& = f.&&ParentObjectUid&& and fo.&&ParentObjectId&& = f.&&ParentObjectId&&
                where f.&&IsParent&& = 1 and
                    f.&&Recipient&& = p_Recipient and
                    f.&&ChangeDateHash&& < p_ChangeDateHash
                order by f.&&ChangeDateHash&& desc
                limit($1)
            loop
                begin

                    &&Id&& = v_TableRecord.&&Id&&;
                    &&Subject&& = v_TableRecord.&&Subject&&;
                    &&Text&& = v_TableRecord.&&Text&&;
                    &&TextHtml&& = v_TableRecord.&&TextHtml&&;
                    &&ActionObjectUid&& = v_TableRecord.&&ActionObjectUid&&;
                    &&ActionUid&& = v_TableRecord.&&ActionUid&&;
                    &&ActionObjectId&& = v_TableRecord.&&ActionObjectId&&;
                    &&Recipient&& = v_TableRecord.&&Recipient&&;
                    &&CreationDate&& = v_TableRecord.&&CreationDate&&;
                    &&ChangeDate&& = v_TableRecord.&&ChangeDate&&;
                    &&CreationAuthor&& = v_TableRecord.&&CreationAuthor&&;
                    &&IsParent&& = v_TableRecord.&&IsParent&&;
                    &&ParentObjectId&& = v_TableRecord.&&ParentObjectId&&;
                    &&ParentObjectUid&& = v_TableRecord.&&ParentObjectUid&&;
                    &&IsRead&& = v_TableRecord.&&IsRead&&;
                    &&HasUnreadChild&& = v_TableRecord.&&HasUnreadChild&&;
                    &&UnreadCount&& = v_TableRecord.&&UnreadCount&&;
                    &&Priority&& = v_TableRecord.&&Priority&&;
                    &&ChangeDateHash&& = v_TableRecord.&&ChangeDateHash&&;
                    &&ChildCount&& = v_TableRecord.&&ChildCount&&;
                    &&MessageAttachments&& = v_TableRecord.&&MessageAttachments&&;
                    &&ObjectRecipients&& = v_TableRecord.&&ObjectRecipients&&;
                    &&MessageObjects&& = v_TableRecord.&&MessageObjects&&;
                    &&Url&& = v_TableRecord.&&Url&&;

                    return next;

                         -- childs
                    for v_TableRecord2 in 
                        select f.&&Id&&, f.&&Subject&&, f.&&Text&&, f.&&TextHtml&&, f.&&ActionObjectUid&&, f.&&ActionUid&&, f.&&ActionObjectId&&, f.&&Recipient&&,
                            f.&&CreationDate&&, f.&&ChangeDate&&, f.&&CreationAuthor&&,
                            f.&&IsRead&&, f.&&HasUnreadChild&&, f.&&UnreadCount&&,
                            f.&&Priority&&, f.&&ChangeDateHash&&, f.&&IsParent&&, f.&&ChildCount&&, f.&&MessageAttachments&&, f.&&ObjectRecipients&&, f.&&MessageObjects&&, f.&&Url&&
                        from &&Feed&& f
                        where f.&&IsParent&& = 0 and
                              f.&&Recipient&& = p_Recipient and
                              f.&&ParentObjectUid&& = v_TableRecord.&&ParentObjectUid&& and
                              f.&&ParentObjectId&& = v_TableRecord.&&ParentObjectId&& and
                              (P_ToDate is null or f.&&ChangeDate&& <= P_ToDate) and
                              (f.&&CreationAuthor&& in (select ffa.&&Id&& from &&FeedFilterAuthors&& ffa)) and
                  (P_OnlyUnread = 0 or f.&&IsRead&& = 0) and
                              (&&FastSearch&& is null or lower(f.&&Text&&) like &&FastSearch&& or lower(f.&&Subject&&) like &&FastSearch&&)
                        order by f.&&ChangeDateHash&& desc
                        limit($1)
                    loop
                        begin

                            &&Id&& = v_TableRecord2.&&Id&&;
                            &&Subject&& = v_TableRecord2.&&Subject&&;
                            &&Text&& = v_TableRecord2.&&Text&&;
                            &&TextHtml&& = v_TableRecord2.&&TextHtml&&;
                            &&ActionObjectUid&& = v_TableRecord2.&&ActionObjectUid&&;
                            &&ActionUid&& = v_TableRecord2.&&ActionUid&&;
                            &&ActionObjectId&& = v_TableRecord2.&&ActionObjectId&&;
                            &&Recipient&& = v_TableRecord2.&&Recipient&&;
                            &&CreationDate&& = v_TableRecord2.&&CreationDate&&;
                            &&ChangeDate&& = v_TableRecord2.&&ChangeDate&&;
                            &&CreationAuthor&& = v_TableRecord2.&&CreationAuthor&&;
                            &&IsParent&& = v_TableRecord2.&&IsParent&&;
                            &&IsRead&& = v_TableRecord2.&&IsRead&&;
                            &&HasUnreadChild&& = v_TableRecord2.&&HasUnreadChild&&;
                            &&UnreadCount&& = v_TableRecord2.&&UnreadCount&&;
                            &&Priority&& = v_TableRecord2.&&Priority&&;
