/**************************************************************************************

   Поиск в избранных сообщениях

**************************************************************************************/
create or replace function FeedFavoritsSearch (
    &&MaxCount&& bigint,            --$1
    p_Recipient bigint,            --$2
    p_ChangeDateHash varchar(16),    --$3    
    &&FastSearch&& varchar(255),        --$4
    P_FromDate timestamp,        --$5
    P_ToDate timestamp,            --$6
    P_Authors text,            --$7    
    P_OnlyUnread smallint        --$8
)
returns table(
    &&Id&& bigint,
    &&Subject&& text,
    &&Text&& text,
    &&TextHtml&& text,
    &&ActionObjectUid&& uuid,
    &&ActionUid&& uuid,
    &&ActionObjectId&& bigint,
    &&Recipient&& bigint,
    &&CreationDate&& timestamp,
    &&ChangeDate&& timestamp,
    &&CreationAuthor&& bigint,
    &&IsParent&& smallint,
    &&ParentObjectId&& bigint,
    &&ParentObjectUid&& uuid,
    &&IsRead&& smallint,
    &&HasUnreadChild&& smallint,
    &&UnreadCount&& integer,
    &&Priority&& integer,
    &&ChangeDateHash&& varchar(35),
    &&ChildCount&& integer,
    &&MessageAttachments&& bytea,
    &&ObjectRecipients&& bytea,
    &&MessageObjects&& bytea,
    &&Url&& varchar(2000))
as
$$

declare
v_TableRecord record;
v_TableRecord2 record;

begin

    p_ChangeDateHash = coalesce(p_ChangeDateHash, 'zzzzzzzzzzzzzzzzzzzzzzzzzzzzzzzzzzz');

    create temporary table if not exists &&FeedObjectId&& 
    (
        &&ChangeDateHash&& varchar(16),
        &&ParentObjectUid&& uuid,
        &&ParentObjectId&& bigint,
        &&IsArchive&& smallint
        ) on commit delete rows;

    if (P_Authors is null) then
        begin

            insert into &&FeedObjectId&& (&&ChangeDateHash&&, &&ParentObjectUid&&, &&ParentObjectId&&, &&IsArchive&&)
                select distinct f.&&FavoriteChangeDateHash&&, f.&&ParentObjectUid&&, f.&&ParentObjectId&&, min(f.&&IsArchive&&)
                from (
                    select ff.&&ChangeDateHash&& &&FavoriteChangeDateHash&&, fp.&&ParentObjectUid&&, fp.&&ParentObjectId&&, 0 &&IsArchive&&
                    from &&Feed&& fp
                        inner join &&FeedFavorite&& ff on ff.&&ActionObjectUid&& = fp.&&ParentObjectUid&& and ff.&&ActionObjectId&& = fp.&&ParentObjectId&& and ff.&&Recipient&& = fp.&&Recipient&& and ff.&&IsDelete&& = 0
                    where
                        fp.&&IsParent&& = 1
                        and fp.&&Recipient&& = p_Recipient
                        and fp.&&ChangeDate&& >= P_FromDate
                        and (P_ToDate is null or fp.&&ChangeDate&& <= P_ToDate)
                        and ff.&&ChangeDateHash&& < p_ChangeDateHash
                        and (&&FastSearch&& is null or lower(fp.&&Text&&) like &&FastSearch&& or lower(fp.&&Subject&&) like &&FastSearch&&)
                    group by ff.&&ChangeDateHash&&, fp.&&ParentObjectUid&&, fp.&&ParentObjectId&&

                    union all

                    select ff.&&ChangeDateHash&& &&FavoriteChangeDateHash&&, fp.&&ParentObjectUid&&, fp.&&ParentObjectId&&, 1 &&IsArchive&&
                    from &&FeedArchive&& fp
                        inner join &&FeedFavorite&& ff on ff.&&ActionObjectUid&& = fp.&&ParentObjectUid&& and ff.&&ActionObjectId&& = fp.&&ParentObjectId&& and ff.&&Recipient&& = fp.&&Recipient&& and ff.&&IsDelete&& = 0
                    where fp.&&IsParent&& = 1
                        and fp.&&Recipient&& = p_Recipient
                        and fp.&&ChangeDate&& >= P_FromDate
                        and (P_ToDate is null or fp.&&ChangeDate&& <= P_ToDate)
                        and ff.&&ChangeDateHash&& < p_ChangeDateHash
                        and (&&FastSearch&& is null or lower(fp.&&Text&&) like &&FastSearch&& or lower(fp.&&Subject&&) like &&FastSearch&&)
                    group by ff.&&ChangeDateHash&&, fp.&&ParentObjectUid&&, fp.&&ParentObjectId&&) F
                group by f.&&FavoriteChangeDateHash&&, f.&&ParentObjectUid&&, f.&&ParentObjectId&&
                order by f.&&FavoriteChangeDateHash&& desc;

            for v_TableRecord in 
                select f.&&Id&&, f.&&Subject&&, f.&&Text&&, f.&&TextHtml&&, f.&&ActionObjectUid&&, f.&&ActionUid&&, f.&&ActionObjectId&&, f.&&Recipient&&,
