                        from &&FeedArchive&& fa right join &&FeedObject&& fo on fo.&&IsArchive&& = 1 and fo.&&ParentObjectUid&& = fa.&&ParentObjectUid&& and fo.&&ParentObjectId&& = fa.&&ParentObjectId&&
                        where fa.&&IsParent&& = 1 and
