                                f1.&&ChangeDate&&, f1.&&CreationAuthor&&, f1.&&IsRead&&, f1.&&HasUnreadChild&&, f1.&&UnreadCount&&, f1.&&Priority&&, f1.&&ChangeDateHash&&,
                                f1.&&IsParent&&, f1.&&ParentObjectId&&, f1.&&ParentObjectUid&&, f1.&&ChildCount&&, f1.&&MessageAttachments&&, f1.&&ObjectRecipients&&, f1.&&MessageObjects&&, f1.&&Url&&
