                                    f.&&Recipient&& = p_Recipient and
                                    v_TableRecord.&&IsArchive&& = 0 and
                                    f.&&ParentObjectUid&& = v_TableRecord.&&ParentObjectUid&& and
                                    f.&&ParentObjectId&& = v_TableRecord.&&ParentObjectId&& and
                                    (P_ToDate is null or f.&&ChangeDate&& <= P_ToDate) and
                                    (f.&&CreationAuthor&& in (select ffa.&&Id&& from &&FeedFilterAuthors&& ffa)) and
                                    (&&FastSearch&& is null or lower(f.&&Text&&) like &&FastSearch&& or lower(f.&&Subject&&) like &&FastSearch&&)
                                limit($1)
                                ) f1

                            union all

                            select f2.&&Id&&, f2.&&Subject&&, f2.&&Text&&, f2.&&TextHtml&&, f2.&&ActionObjectUid&&, f2.&&ActionUid&&, f2.&&ActionObjectId&&, f2.&&Recipient&&, f2.&&CreationDate&&,
                                f2.&&ChangeDate&&, f2.&&CreationAuthor&&, f2.&&IsRead&&, f2.&&HasUnreadChild&&, f2.&&UnreadCount&&, f2.&&Priority&&, f2.&&ChangeDateHash&&,
                                f2.&&IsParent&&, f2.&&ParentObjectId&&, f2.&&ParentObjectUid&&, f2.&&ChildCount&&, f2.&&MessageAttachments&&, f2.&&ObjectRecipients&&, f2.&&MessageObjects&&, f2.&&Url&&
                            from (
                                select fa.&&Id&&, fa.&&Subject&&, fa.&&Text&&, fa.&&TextHtml&&, fa.&&ActionObjectUid&&, fa.&&ActionUid&&,
                                    fa.&&ActionObjectId&&, fa.&&Recipient&&, fa.&&CreationDate&&, fa.&&ChangeDate&&, fa.&&CreationAuthor&&,
