/**************************************************************************************

   Загружает комментарии к сообщению ленты.

**************************************************************************************/
create or replace function FeedCommentsLoad(
    p_Recipient bigint,
    p_ParentObjectUid  uuid,
    p_ParentObjectId bigint,
    p_ChangeDateHash CHAR(35),
    p_MaxChildCount bigint
)
returns table(
    &&Id&& bigint,
    &&Subject&& text,
    &&Text&& text,
    &&TextHtml&& text,
    &&ActionObjectUid&& uuid,
    &&ActionUid&& uuid,
    &&ActionObjectId&& bigint,
    &&Recipient&& bigint,
    &&CreationDate&& timestamp,
    &&ChangeDate&& timestamp,
    &&CreationAuthor&& bigint,
    &&IsParent&& smallint,
    &&ParentObjectId&& bigint,
    &&ParentObjectUid&& uuid,
    &&IsRead&& smallint,
    &&ReadDate&& timestamp,
    &&HasUnreadChild&& smallint,
    &&UnreadCount&& integer,
    &&Priority&& integer,
    &&ChangeDateHash&& varchar(35),
    &&ChildCount&& integer,
    &&MessageAttachments&& bytea,
    &&ObjectRecipients&& bytea,
    &&MessageObjects&& bytea,
    &&Url&& varchar(2000))

as
$$

declare
v_TableRecord record;

begin

    for v_TableRecord in 
        select f1.&&Id&&, f1.&&Subject&&, f1.&&Text&&, f1.&&TextHtml&&, f1.&&ActionObjectUid&&, f1.&&ActionUid&&, f1.&&ActionObjectId&&, f1.&&Recipient&&, f1.&&CreationDate&&,
            f1.&&ChangeDate&&, f1.&&CreationAuthor&&, f1.&&IsParent&&, f1.&&ParentObjectId&&, f1.&&ParentObjectUid&&,
            f1.&&IsRead&&, f1.&&ReadDate&&,
            f1.&&HasUnreadChild&&, f1.&&UnreadCount&&, f1.&&Priority&&, f1.&&ChangeDateHash&&, f1.&&ChildCount&&,
            f1.&&MessageAttachments&&, f1.&&ObjectRecipients&&, f1.&&MessageObjects&&, f1.&&Url&&
        from &&Feed&& f1
        where f1.&&ParentObjectId&& = p_ParentObjectId
            and f1.&&ParentObjectUid&& = p_ParentObjectUid
            and f1.&&Recipient&& = p_Recipient
            and f1.&&IsParent&& = 1

        union all

        select fc.&&Id&&, fc.&&Subject&&, fc.&&Text&&, fc.&&TextHtml&&, fc.&&ActionObjectUid&&, fc.&&ActionUid&&, fc.&&ActionObjectId&&, fc.&&Recipient&&, fc.&&CreationDate&&,
            fc.&&ChangeDate&&, fc.&&CreationAuthor&&, fc.&&IsParent&&, fc.&&ParentObjectId&&, fc.&&ParentObjectUid&&,
            fc.&&IsRead&&, fc.&&ReadDate&&,
            fc.&&HasUnreadChild&&, fc.&&UnreadCount&&, fc.&&Priority&&, fc.&&ChangeDateHash&&, fc.&&ChildCount&&,
            fc.&&MessageAttachments&&, fc.&&ObjectRecipients&&, fc.&&MessageObjects&&, fc.&&Url&&
        from (
            select f.*
            from &&Feed&& f
            where f.&&ParentObjectId&& = p_ParentObjectId
                and f.&&ParentObjectUid&& = p_ParentObjectUid
                and f.&&Recipient&& = p_Recipient
                and f.&&IsParent&& = 0
                and f.&&ChangeDateHash&& < coalesce(p_ChangeDateHash, 'zzzzzzzzzzzzzzzzzzzzzzzzzzzzzzzzzzz')
            order by f.&&ChangeDateHash&& desc
            limit(p_MaxChildCount)
            ) fc
    loop
        begin

            &&Id&& = v_TableRecord.&&Id&&;
            &&Subject&& = v_TableRecord.&&Subject&&;
            &&Text&& = v_TableRecord.&&Text&&;
            &&TextHtml&& = v_TableRecord.&&TextHtml&&;
            &&ActionObjectUid&& = v_TableRecord.&&ActionObjectUid&&;
            &&ActionUid&& = v_TableRecord.&&ActionUid&&;
            &&ActionObjectId&& = v_TableRecord.&&ActionObjectId&&;
            &&Recipient&& = v_TableRecord.&&Recipient&&;
            &&CreationDate&& = v_TableRecord.&&CreationDate&&;
            &&ChangeDate&& = v_TableRecord.&&ChangeDate&&;
            &&CreationAuthor&& = v_TableRecord.&&CreationAuthor&&;
            &&IsParent&& = v_TableRecord.&&IsParent&&;
            &&ParentObjectId&& = v_TableRecord.&&ParentObjectId&&;
            &&ParentObjectUid&& = v_TableRecord.&&ParentObjectUid&&;
            &&IsRead&& = v_TableRecord.&&IsRead&&;
            &&ReadDate&& = v_TableRecord.&&ReadDate&&;
            &&HasUnreadChild&& = v_TableRecord.&&HasUnreadChild&&;
            &&UnreadCount&& = v_TableRecord.&&UnreadCount&&;
            &&Priority&& = v_TableRecord.&&Priority&&;
            &&ChangeDateHash&& = v_TableRecord.&&ChangeDateHash&&;
            &&ChildCount&& = v_TableRecord.&&ChildCount&&;
            &&MessageAttachments&& = v_TableRecord.&&MessageAttachments&&;
            &&ObjectRecipients&& = v_TableRecord.&&ObjectRecipients&&;
            &&MessageObjects&& = v_TableRecord.&&MessageObjects&&;
            &&Url&& = v_TableRecord.&&Url&&;

            return next;

        end;
    end loop;
end;

$$
language plpgsql;

/**************************************************************************************
Возвращает количество непрочитанных сообщений для заданного пользователя.
**************************************************************************************/ create or replace function FeedGetUnreadCount( &&Recipient&& bigint, &&Priority&& integer ) returns table( &&WithPriority&& smallint, &&Count&& bigint )
as $$
declare v_TableRecord record;
begin
for v_TableRecord in select 1 &&WithPriority&&, count(f.&&Id&&) &&Count&& from &&Feed&& f where f.&&Recipient&& = $1 and (f.&&IsRead&& = 0) and (f.&&Priority&& >= $2)
union
select 0 &&WithPriority&&, count(f.&&Id&&) &&Count&& from &&Feed&& f where f.&&Recipient&& = $1 and (f.&&IsRead&& = 0) loop begin
&&WithPriority&& = v_TableRecord.&&WithPriority&&; &&Count&& = v_TableRecord.&&Count&&;
return next; end; end loop; end
$$ language plpgsql;


/**************************************************************************************

   Создаёт заданное количество идентификаторов для таблицы Feed и возвращает первый из них.

**************************************************************************************/
create or replace function FeedGetNewIds(
    p_Count bigint
)
returns bigint

as
$$

declare 
v_firstId bigint = 0;
v_anotherId bigint = 0;

begin
    while p_Count > 0 loop
        if (v_firstId = 0) then
            begin
                v_firstId = nextval('G_FEED');
            end;
        else
            begin
                v_anotherId = nextval('G_FEED');
            end;
        end if;
        p_Count = p_Count - 1;
    end loop;

    return v_firstId;
end
$$
language plpgsql;

/**************************************************************************************
Возвращает первый hash из ленты сообщений.
**************************************************************************************/ create or replace function FeedChangeDateHashFirst(p_Recipient bigint) returns varchar(35)
as $$
declare &&ChangeDateHash&& varchar(35);
begin
select f.&&ChangeDateHash&& from &&Feed&& f where &&IsParent&& = 1 and &&Recipient&& = $1 order by f.&&ChangeDateHash&& limit(1) into &&ChangeDateHash&&;
return &&ChangeDateHash&&;
end
$$ language plpgsql;

/**************************************************************************************
Возвращает последний hash из ленты сообщений.
**************************************************************************************/ create or replace function FeedChangeDateHashLast(p_Recipient bigint) returns varchar(35)
as $$
declare &&ChangeDateHash&& varchar(35);
begin
select f.&&ChangeDateHash&& from &&Feed&& f where &&IsParent&& = 1 and &&Recipient&& = $1 order by f.&&ChangeDateHash&& desc limit 1 into &&ChangeDateHash&&;
return &&ChangeDateHash&&;
end
$$ language plpgsql;

/**************************************************************************************
Отметить все сообщения по указанному объекту, как прочитанные.
**************************************************************************************/ create or replace function FeedSetAsReadForObject( &&ReadDate&& timestamp, &&ParentObjectUid&& uuid, &&ParentObjectId&& bigint, &&Recipient&& bigint ) returns void
as $$
begin
update &&Feed&& f set &&IsRead&& = 1, &&HasUnreadChild&& = (case when &&IsParent&& = 1 then 0 else null end), &&UnreadCount&& = 0, &&ReadDate&& = $1 where f.&&ParentObjectUid&& = $2 and f.&&ParentObjectId&& = $3 and f.&&Recipient&& = $4;
end $$ language plpgsql;

/**************************************************************************************
Получить идентификаторы сообщений после указанной даты.
**************************************************************************************/ create or replace function FeedGetReadedPostsIds( &&Recipient&& bigint, &&IsRead&& smallint, &&FromDate&& timestamp ) returns setof bigint
as $$
begin
return query select f.&&Id&& from &&Feed&& f where f.&&Recipient&& = $1 and f.&&IsRead&& = $2 and ((cast(coalesce(&&ReadDate&&, cast('01-01-1753' as timestamp)) as timestamp) > cast(coalesce($3, cast('01-01-1753' as timestamp)) as timestamp)) or (&&ReadDate&& is null and $3 is null));
return;
end $$ language plpgsql;


/**************************************************************************************

   Загружает сообщения без комментариев.

**************************************************************************************/
create or replace function FeedLoadMessages(Ids text)
returns table(
    &&Id&& bigint,
    &&Subject&& text,
    &&Text&& text,
    &&TextHtml&& text,
    &&ActionObjectUid&& uuid,
    &&ActionUid&& uuid,
    &&ActionObjectId&& bigint,
    &&Recipient&& bigint,
    &&CreationDate&& timestamp,
    &&ChangeDate&& timestamp,
    &&CreationAuthor&& bigint,
    &&IsParent&& smallint,
    &&ParentObjectId&& bigint,
    &&ParentObjectUid&& uuid,
    &&IsRead&& smallint,
    &&ReadDate&& timestamp,
    &&HasUnreadChild&& smallint,
    &&UnreadCount&& integer,
    &&Priority&& integer,
    &&ChangeDateHash&& varchar(35),
    &&ChildCount&& integer,
    &&MessageAttachments&& bytea,
    &&ObjectRecipients&& bytea,
    &&MessageObjects&& bytea,
    &&Url&& varchar(2000))

as
$$

declare
v_TableRecord record;

begin

    for v_TableRecord in
        select f.&&Id&&, f.&&Subject&&, f.&&Text&&, f.&&TextHtml&&, f.&&ActionObjectUid&&, f.&&ActionUid&&, f.&&ActionObjectId&&, f.&&Recipient&&, f.&&CreationDate&&,
               f.&&ChangeDate&&, f.&&CreationAuthor&&, f.&&IsParent&&, f.&&ParentObjectId&&, f.&&ParentObjectUid&&,
               f.&&IsRead&&, f.&&ReadDate&&,
               f.&&HasUnreadChild&&, f.&&UnreadCount&&, f.&&Priority&&, f.&&ChangeDateHash&&, f.&&ChildCount&&,
               f.&&MessageAttachments&&, f.&&ObjectRecipients&&, f.&&MessageObjects&&, f.&&Url&&
        from &&Feed&& f
        where f.&&IsParent&& = 1 and f.&&Id&& in (select cast(&&Val&& as bigint) as &&Id&& from SplitString($1, ','))
    loop
        begin

            &&Id&& = v_TableRecord.&&Id&&;
            &&Subject&& = v_TableRecord.&&Subject&&;
            &&Text&& = v_TableRecord.&&Text&&;
            &&TextHtml&& = v_TableRecord.&&TextHtml&&;
            &&ActionObjectUid&& = v_TableRecord.&&ActionObjectUid&&;
            &&ActionUid&& = v_TableRecord.&&ActionUid&&;
            &&ActionObjectId&& = v_TableRecord.&&ActionObjectId&&;
            &&Recipient&& = v_TableRecord.&&Recipient&&;
            &&CreationDate&& = v_TableRecord.&&CreationDate&&;
            &&ChangeDate&& = v_TableRecord.&&ChangeDate&&;
            &&CreationAuthor&& = v_TableRecord.&&CreationAuthor&&;
            &&IsParent&& = v_TableRecord.&&IsParent&&;
            &&ParentObjectId&& = v_TableRecord.&&ParentObjectId&&;
            &&ParentObjectUid&& = v_TableRecord.&&ParentObjectUid&&;
            &&IsRead&& = v_TableRecord.&&IsRead&&;
            &&ReadDate&& = v_TableRecord.&&ReadDate&&;
            &&HasUnreadChild&& = v_TableRecord.&&HasUnreadChild&&;
            &&UnreadCount&& = v_TableRecord.&&UnreadCount&&;
            &&Priority&& = v_TableRecord.&&Priority&&;
            &&ChangeDateHash&& = v_TableRecord.&&ChangeDateHash&&;
            &&ChildCount&& = v_TableRecord.&&ChildCount&&;
            &&MessageAttachments&& = v_TableRecord.&&MessageAttachments&&;
            &&ObjectRecipients&& = v_TableRecord.&&ObjectRecipients&&;
            &&MessageObjects&& = v_TableRecord.&&MessageObjects&&;
            &&Url&& = v_TableRecord.&&Url&&;

            return next;
        end;
    end loop;
end
$$
language plpgsql;

/**************************************************************************************
Пересчитать счётчики количества дочерних сообщений и количества непрочитанных дочерних сообщений.
**************************************************************************************/ create or replace function FeedChildCountRecalc() returns void
as $$
declare v_TableRecord record;
begin
for v_TableRecord in select f.&&ParentObjectId&&, f.&&ParentObjectUid&&, f.&&Recipient&&, count(f.&&Id&&) &&ChildCount&& from &&Feed&& f where f.&&IsParent&& = 0 group by f.&&ParentObjectId&&, f.&&ParentObjectUid&&, f.&&Recipient&& loop begin update &&Feed&& set &&ChildCount&& = v_TableRecord.&&ChildCount&& where &&IsParent&& = 1 and &&ParentObjectId&& = v_TableRecord.&&ParentObjectId&& and &&ParentObjectUid&& = v_TableRecord.&&ParentObjectUid&& and &&Recipient&& = v_TableRecord.&&Recipient&&; end;
end loop;
for v_TableRecord in select f.&&ParentObjectId&&, f.&&ParentObjectUid&&, f.&&Recipient&&, count(f.&&Id&&) &&ChildCount&& from &&Feed&& f where f.&&IsParent&& = 0 and f.&&IsRead&& = 0 group by f.&&ParentObjectId&&, f.&&ParentObjectUid&&, f.&&Recipient&& loop begin update &&Feed&& set &&UnreadCount&& = v_TableRecord.&&ChildCount&&, &&HasUnreadChild&& = (case when v_TableRecord.&&ChildCount&& = 0 then 0 else 1 end) where &&IsParent&& = 1 and &&ParentObjectId&& = v_TableRecord.&&ParentObjectId&& and &&ParentObjectUid&& = v_TableRecord.&&ParentObjectUid&& and &&Recipient&& = v_TableRecord.&&Recipient&&; end; end loop;
end
$$ language plpgsql;
